void CollectData(int[] addrs, Action<int, ushort> callback) {
    foreach (var addr in addrs) {
        ushort val = Plc.ReadHoldingRegister(addr);
        callback(addr, val);
    }
}

void OnDataReady(int addr, ushort val) {
    Print($"地址{addr}: 数据={val}");
}

int[] addrs = { 100, 101, 102, 103, 104 };
CollectData(addrs, OnDataReady);
Print("采集完成");
